-- Curated India hospital equipment catalogue (536 items, 6 categories).
-- Sourced from user-supplied Hospital_Equipment_Catalogue.xlsx (committed
-- as data/hospital_equipment_catalogue.json). Backs marketplace browse
-- with brand/model/specs and INR price bands so buyers can see realistic
-- reference data even when no real seller has listed yet.

CREATE TABLE IF NOT EXISTS public.catalog_reference_items (
  id int PRIMARY KEY,
  category text NOT NULL,
  sub_category text,
  item_name text NOT NULL,
  brand text,
  model text,
  type text,
  key_specifications text,
  price_inr_low bigint,
  price_inr_high bigint,
  notes text,
  created_at timestamptz NOT NULL DEFAULT now()
);

CREATE INDEX IF NOT EXISTS catalog_ref_category_idx ON public.catalog_reference_items (category);
CREATE INDEX IF NOT EXISTS catalog_ref_brand_idx    ON public.catalog_reference_items (lower(brand));
CREATE INDEX IF NOT EXISTS catalog_ref_search_idx
  ON public.catalog_reference_items
  USING gin (to_tsvector('simple',
    coalesce(item_name,'') || ' ' ||
    coalesce(brand,'')     || ' ' ||
    coalesce(model,'')     || ' ' ||
    coalesce(sub_category,'') || ' ' ||
    coalesce(key_specifications,'')
  ));

ALTER TABLE public.catalog_reference_items ENABLE ROW LEVEL SECURITY;

DROP POLICY IF EXISTS catalog_ref_public_read ON public.catalog_reference_items;
CREATE POLICY catalog_ref_public_read
  ON public.catalog_reference_items FOR SELECT TO authenticated, anon
  USING (true);

-- Re-seed: nuke and reload so re-running the migration after a catalogue
-- refresh keeps the table consistent.
TRUNCATE public.catalog_reference_items;

